function parseRange(s) {
  if (s.includes('-')) {
    const [a, b] = s.split('-').map(Number);
    const arr = [];
    if (a <= b) {
      for (let i = a; i <= b; i++) arr.push(i);
    } else {
      for (let i = a; i >= b; i--) arr.push(i);
    }
    return arr;
  }
  return [Number(s)];
}
